# Write your MySQL query statement below
select round( AVG(d.order_date = d.customer_pref_delivery_date) * 100, 2 ) as immediate_percentage from Delivery d JOIN ( SELECT customer_id, MIN(order_date) as first_order from Delivery group by customer_id ) f ON d.customer_id = f.customer_id and d.order_date = f.first_order;